const { jobUrl, requestId, submittedAt } = $input.first().json;

if (!jobUrl) {
  throw new Error('jobUrl is required');
}

// Normalize URL
let canonical = jobUrl.trim();
if (!canonical.startsWith('http')) {
  canonical = 'https://' + canonical;
}

// Remove tracking params
const url = new URL(canonical);
url.searchParams.delete('utm_source');
url.searchParams.delete('utm_medium');
url.searchParams.delete('utm_campaign');
canonical = url.toString();

// Detect source
let source = 'other';
if (canonical.includes('greenhouse.io')) source = 'greenhouse';
else if (canonical.includes('lever.co')) source = 'lever';
else if (canonical.includes('linkedin.com')) source = 'linkedin';
else if (canonical.includes('indeed.com')) source = 'indeed';
else if (canonical.includes('workday.com')) source = 'workday';

return {
  jobUrl: canonical,
  requestId: requestId || crypto.randomUUID(),
  submittedAt: submittedAt || new Date().toISOString(),
  source
};

const html = $input.first().json.body;
const source = $('Normalize URL').first().json.source;

let title = '';
let company = '';
let location = '';
let description = '';
let salary = '';

// Extract title
const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
if (titleMatch) {
  title = titleMatch[1].split(' at ')[0].split(' - ')[0].trim();
}

// Source-specific parsing
if (source === 'greenhouse') {
  const companyMatch = html.match(/"company"\s*:\s*"([^"]+)"/i) ||
                       html.match(/<meta[^>]*property="og:title"[^>]*content="[^"]*at ([^"]+)"/i);
  if (companyMatch) company = companyMatch[1];

  const locMatch = html.match(/"location"\s*:\s*"([^"]+)"/i) ||
                   html.match(/<div[^>]*class="[^"]*location[^"]*"[^>]*>([^<]+)<\/div>/i);
  if (locMatch) location = locMatch[1];

  const descMatch = html.match(/<div[^>]*id="content"[^>]*>([\s\S]*?)<\/div>/i);
  if (descMatch) description = descMatch[1].replace(/<[^>]+>/g, ' ').substring(0, 5000);
}
else if (source === 'lever') {
  const companyMatch = html.match(/<a[^>]*class="[^"]*company-name[^"]*"[^>]*>([^<]+)<\/a>/i);
  if (companyMatch) company = companyMatch[1];

  const locMatch = html.match(/<span[^>]*class="[^"]*location[^"]*"[^>]*>([^<]+)<\/span>/i);
  if (locMatch) location = locMatch[1];
}
else if (source === 'linkedin') {
  const companyMatch = html.match(/<a[^>]*class="[^"]*company-name[^"]*"[^>]*>([^<]+)<\/a>/i) ||
                       html.match(/"hiringOrganization"\s*:\s*\{[^}]*"name"\s*:\s*"([^"]+)"/i);
  if (companyMatch) company = companyMatch[1];
}
else {
  // Generic fallback
  const h1Match = html.match(/<h1[^>]*>([^<]+)<\/h1>/i);
  if (h1Match && !title) title = h1Match[1];
}

// Clean up
title = title.replace(/\s+/g, ' ').trim();
company = company.replace(/\s+/g, ' ').trim();
location = location.replace(/\s+/g, ' ').trim();
description = description.replace(/\s+/g, ' ').trim();

// Calculate fingerprint
const fingerprint = Buffer.from(`${company}|${title}|${location}`).toString('base64');

return {
  title: title || 'Unknown Position',
  company: company || 'Unknown Company',
  location: location || '',
  description: description || '',
  salary: salary || '',
  fingerprint_hash: fingerprint,
  parse_quality: (title && company) ? 'full' : 'partial',
  parse_missing_fields: [
    ...(!title ? ['title'] : []),
    ...(!company ? ['company'] : []),
    ...(!description ? ['description'] : [])
  ]
};

