const response = $input.first().json;
let result = { score: 50, fit: 'MEDIUM', strengths: [], gaps: [], reasoning: '' };

try {
  const content = response.choices[0].message.content;
  // Try to parse JSON from response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    result = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  console.log('Failed to parse scoring response:', e.message);
}

// Normalize fit
if (result.score >= 80) result.fit = 'HIGH';
else if (result.score >= 50) result.fit = 'MEDIUM';
else result.fit = 'LOW';

return result;
